      block_strided ? static_cast<long>(workgroupsize) : compute_grid_size;
  const long big_stride = compute_grid_size * static_cast<long>(elements_per_wi);

#pragma omp parallel for schedule(static)
  for (long gid = 0; gid < compute_grid_size; gid++) {
