          kernel_time_mad_int * 1000.0 / (1000.0 * 1000.0 * 1000.0));
}

void mixbenchCPU(void* buffer_void, size_t size_bytes) {
  unsigned char* buffer = static_cast<unsigned char*>(buffer_void);
  const long size = static_cast<long>(size_bytes / sizeof(double));

  const bool block_strided = false;
  const bool host_allocated = true;
  const bool use_os_timer = true;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  printf("Buffer size:            %zuMB\n", size_bytes / (1024 * 1024));
  printf("Workgroup size:         %d\n", static_cast<int>(workgroupsize));
  printf("Elements per workitem:  %d\n", elements_per_wi);
  printf("Workitem fusion degree: %d\n", fusion_degree);
  printf("Workitem stride:        %s\n", block_strided ? "Workgroup" : "NDRange");
  printf("Buffer allocation:      %s\n",
         host_allocated ? "Host allocated" : "Device allocated");
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  std::memset(buffer, 0, size_bytes);

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    show_progress_step(0, '/');
    show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(buffer, size);

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, buffer, size, workgroupsize,
             elements_per_wi, fusion_degree, block_strided);
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");
}
